import http from '../http'

interface Rolelist {
    roleName?: string,
    roleRemark?: string
}
// 角色列表
export function roleList(options: Rolelist) {
    return http.get('/jkyErp/role/list', options)
}

interface Addrole {
    roleName: string,
    roleRemark?: string
}
// 新增角色
export function addRole(options: Addrole) {
    return http.post('/jkyErp/role/add', options)
}

interface Editrole {
    roleId: number
    roleName: string,
    roleRemark?: string
}
// 修改角色
export function editRole(options: Editrole) {
    return http.post('/jkyErp/role/edit', options)
}


// 删除角色
export function delRole(roleId: number) {
    return http.post(`/jkyErp/role/remove/${roleId}`)
}

// 查看所有权限
export function getAllMenu() {
    return http.get(`/jkyErp/userFunction/getAllMenu_peer`)
}
// 查看角色权限
export function getRoleMenu(roleId: number) {
    return http.get(`/jkyErp/userFunction/getRoleMenu`, { roleId })
}
// 分配权限
interface Grant {
    roleId: number
    list: []
}
export function grant(options: Grant) {
    return http.post(`/jkyErp/userFunction/grant`, options)
}
// 发布公告
export function postAnnounce(Files: any) {
    return http.post('/jkyErp/home/postAnnounce', Files)
}
// 公告列表
export function showAnnounce() {
    return http.get('/jkyErp/home/showAnnounce')
}
// 首页任务统计
export function taskStatistics() {
    return http.get('/jkyErp/home/taskStatistics')
}
// 首页产值统计
export function outputValueStatistics(flag: any) {
    return http.get('/jkyErp/home/outputValueStatistics', { flag })
}
