
import { ArrowUpOutlined, ArrowDownOutlined } from "@ant-design/icons-vue";
import { defineComponent, onMounted, reactive, ref, toRefs, watch } from "vue";
import {
  taskStatistics,
  outputValueStatistics,
  showAnnounce,
} from "@/server/http/api/system";
import Demo from "./echarts/Demo.vue";
export default defineComponent({
  components: {
    ArrowUpOutlined,
    ArrowDownOutlined,
    Demo,
  },
  setup() {
    let active = ref(1);
    let news = ref([]);
    function buil(type: number) {
      active.value = type;
    }
    let data: any = reactive({
      allTask: 0,
      completeTask: 0,
      incompleteTak: 0,
      outputValue: 0,
    });
    let options = ref([]);

    onMounted(() => {
      taskStatistics().then((res: any) => {
        if (res.data.code === 200) {
          Object.assign(data, res.data.data);
        }
      });
      showAnnounce().then((res: any) => {
        if (res.data.code === 200) {
          news.value = res.data.data;
        }
      });
    });
    return {
      active,
      buil,
      ...toRefs(data),
      options,
      news,
    };
  },
});
