<template>
  <a-card>
    <div :class="advanced ? 'search' : null">
      <a-form layout="horizontal">
        <div :class="advanced ? null : 'fold'">
          <a-row>
            <a-col :md="8" :sm="24">
              <a-form-item
                label="设备名称"
                :labelCol="{ span: 5 }"
                :wrapperCol="{ span: 18, offset: 1 }"
              >
                <a-input
                  placeholder="请输入设备名称"
                  v-model:value="queryParams.name"
                />
              </a-form-item>
            </a-col>
          </a-row>
        </div>
        <span style="float: right; margin-top: 3px">
          <a-button type="primary" @click="handleSearch">查询</a-button>
          <a @click="toggleAdvanced" style="margin-left: 8px">
            {{ advanced ? "收起" : "展开" }}
          </a>
        </span>
      </a-form>
    </div>
    <div>
      <a-space class="operator">
        <a-button @click="handleAdd" type="primary">新建</a-button>
        <a-button
          @click="handleUpdate"
          type="primary"
          :disabled="selectedRowKeys.length == 1 ? false : true"
          >编辑</a-button
        >
        <a-button
          @click="handleDel"
          type="primary"
          :disabled="selectedRowKeys.length > 0 ? false : true"
          danger
          >删除
        </a-button>
        <a-button
          @click="hanleAr"
          type="primary"
          :disabled="selectedRowKeys.length == 1 ? false : true"
          >添加设备检测报告
        </a-button>
      </a-space>
      <a-table
        rowKey="id"
        :pagination="false"
        :columns="columns"
        :customRow="rowClick"
        :data-source="dataSource"
        :row-selection="{
          selectedRowKeys: selectedRowKeys,
          onChange: onSelectChange,
        }"
      >
        <template #isPort="{ text }">
          {{ text == "1" ? "有" : "无" }}
        </template>
      </a-table>
      <a-pagination
        v-show="total > 0"
        show-size-changer
        :show-total="(total) => `共 ${total} 条`"
        v-model:current="queryParams.current"
        v-model:pageSize="queryParams.size"
        :total="total"
        show-less-items
        @showSizeChange="onShowSizeChange"
        @change="onPageChange"
      />
    </div>
  </a-card>

  <a-modal
    :visible="open"
    :title="title"
    width="650px"
    @ok="handleOk"
    @cancel="handleCancel"
  >
    <a-form :model="form" :rules="rules">
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="仪器分类" :rules="[{ required: true }]">
            <a-select
              :allowClear="true"
              showSearch
              optionFilterProp="lable"
              v-model:value="form.typeId"
              placeholder="请选择仪器分类"
            >
              <a-select-option
                v-for="item in selDeviceTypeList"
                :key="item.id"
                :lable="item.name"
                :value="item.id"
              >
                {{ item.name }}
              </a-select-option>
            </a-select>
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="所在实验室" :rules="[{ required: true }]">
            <a-select
              :allowClear="true"
              showSearch
              optionFilterProp="lable"
              v-model:value="form.laboratoryId"
              placeholder="请选择所在实验室"
            >
              <a-select-option
                v-for="item in selLabManageList"
                :key="item.id"
                :lable="item.name"
                :value="item.id"
              >
                {{ item.name }}
              </a-select-option>
            </a-select>
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="仪器名称" name="name">
            <a-input placeholder="请输入仪器名称" v-model:value="form.name" />
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="生产厂家">
            <a-input
              placeholder="请输入生产厂家"
              v-model:value="form.manufacturer"
            />
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="设备编号">
            <a-input placeholder="请输入生成编号" v-model:value="form.code" />
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="旧编号">
            <a-input placeholder="请输入旧编号" v-model:value="form.oldCode" />
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="规格型号">
            <a-input placeholder="请输入规格型号" v-model:value="form.model" />
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="出场编号">
            <a-input
              placeholder="请输入出场编号"
              v-model:value="form.serialNumber"
            />
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="购置价格">
            <a-input-number
              placeholder="请输入购置价格"
              v-model:value="form.price"
            />
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="管理人员" name="deviceAdmin">
            <a-input
              placeholder="请输入管理人员"
              v-model:value="form.deviceAdmin"
            />
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="入编日期">
            <a-date-picker
              v-model:value="form.incorporatedDate"
              type="date"
              valueFormat="yyyy-MM-DD"
              placeholder="请选择入编日期"
              style="width: 100%"
            />
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="最新鉴定日期">
            <a-date-picker
              v-model:value="form.appraisalDate"
              type="date"
              valueFormat="yyyy-MM-DD"
              placeholder="请选择最新鉴定日期"
              style="width: 100%"
            />
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="精度等级">
            <a-input placeholder="请输入精度等级" v-model:value="form.level" />
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="小时单价">
            <a-input-number
              placeholder="请输入小时单价"
              v-model:value="form.pricePerHour"
            />
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="检查费用">
            <a-input-number
              placeholder="请输入检查费用"
              v-model:value="form.checkPrice"
            />
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="仪器量程">
            <a-input placeholder="请输入仪器量程" v-model:value="form.range" />
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="有无串口">
            <a-radio-group v-model:value="form.isPort">
              <a-radio value="0">无</a-radio>
              <a-radio value="1">有</a-radio>
            </a-radio-group>
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="溯源方式">
            <a-input
              placeholder="请输入溯源方式"
              v-model:value="form.administintor"
            />
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="有效期限">
            <a-date-picker
              v-model:value="form.validityDate"
              valueFormat="yyyy-MM-DD"
              type="date"
              placeholder="请选择有效期限"
              style="width: 100%"
            />
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="仪器照片">
            <a-upload
              v-model:file="file"
              :show-upload-list="false"
              :customRequest="pictureCustomRequest"
              :before-upload="pictureBeforeUpload"
            >
              <img
                v-if="form.picture"
                :src="form.picture"
                alt="avatar"
                style="width: 40px; heidht: 40px"
              />
              <div v-else>
                <a-button>
                  <UploadOutlined></UploadOutlined>
                  点击上传图片
                </a-button>
              </div>
            </a-upload>
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="24">
          <a-form-item label="服务内容">
            <a-textarea
              rows="4"
              placeholder="请输入服务内容"
              v-model:value="form.content"
              show-count
              :maxlength="100"
            />
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="合同">
            <a-input v-model:value="form.contractUrl" disabled="true" />
            <a-upload
              v-model:file="file"
              :show-upload-list="false"
              :customRequest="contractUrlCustomRequest"
              :before-upload="contractUrlBeforeUpload"
            >
              <a-button v-if="form.contractUrl">
                <UploadOutlined></UploadOutlined>
                点击修改合同
              </a-button>
              <a-button v-else>
                <UploadOutlined></UploadOutlined>
                点击上传合同
              </a-button>
            </a-upload>
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="发票">
            <a-input v-model:value="form.invoiceUrl" disabled="true" />
            <a-upload
              v-model:file="file"
              :show-upload-list="false"
              :customRequest="invoiceUrlCustomRequest"
              :before-upload="invoiceUrlBeforeUpload"
            >
              <a-button v-if="form.invoiceUrl">
                <UploadOutlined></UploadOutlined>
                点击修改发票
              </a-button>
              <a-button v-else>
                <UploadOutlined></UploadOutlined>
                点击上传发票
              </a-button>
            </a-upload>
          </a-form-item>
        </a-col>
      </a-row>
    </a-form>
  </a-modal>

  <a-modal
    :visible="openAr"
    :title="title"
    width="1100px"
    :footer="null"
    @cancel="handleCancelAr"
  >
    <AppraisalRecord
      :Code="selectedRowKeys[0]"
      :ResList="RecordListRes"
    ></AppraisalRecord>
  </a-modal>
</template>

<script>
import { message } from "ant-design-vue";
import AppraisalRecord from "../../views/deviceManage/AppraisalRecord.vue";
const columns = [
  {
    title: "编号",
    dataIndex: "id",
  },
  {
    title: "仪器名称",
    dataIndex: "name",
  },
  {
    title: "所在实验室",
    dataIndex: "laboratoryName",
  },
  {
    title: "仪器分类",
    dataIndex: "typeName",
    slots: { title: "typeName" },
  },
  {
    title: "设备管理员",
    dataIndex: "deviceAdmin",
    slots: { title: "deviceAdmin" },
  },
  {
    title: "小时/价（元）",
    dataIndex: "pricePerHour",
    slots: { title: "pricePerHour" },
  },
  {
    title: "精度等级",
    dataIndex: "level",
    slots: { title: "level" },
  },
  {
    title: "有无串口",
    dataIndex: "isPort",
    slots: { customRender: "isPort" },
  },
  {
    title: "最新鉴定日期",
    dataIndex: "appraisalDate",
  },
  {
    title: "有效期限",
    dataIndex: "validityDate",
  },
];
const rules = {
  name: [{ required: true, message: "该为必填项", trigger: "blur" }],
  deviceAdmin: [{ required: true, message: "该为必填项", trigger: "blur" }],
};
import {
  UploadOutlined,
  PlusOutlined,
  LoadingOutlined,
} from "@ant-design/icons-vue";
import {
  DeviceList,
  addDevice,
  getDevice,
  delDevice,
  LaboratoryListAll,
  editDevice,
  RecordList,
  DeviceTypeListAll,
} from "@/server/http/api/Device";
import { uploadFile, delFile } from "@/server/http/api/File";
import Index from "../index/Index.vue";
export default {
  name: "QueryList",
  components: {
    AppraisalRecord,
    UploadOutlined,
    Index,
    PlusOutlined,
    LoadingOutlined,
  },
  data() {
    return {
      // 弹出层标题
      title: "",
      // 是否显示弹出层（设备）
      open: false,
      // 是否显示弹出层（检查报告）
      openAr: false,
      advanced: false,
      columns: columns,
      rules: rules,
      dataSource: [],
      selectedRows: [],
      selectedRowKeys: [],
      file: null,
      // 表单参数
      form: {},
      Pagination: {},
      total: 0,

      queryParams: {
        current: 1,
        size: 10,
        orders: [],
        name: undefined,
      },
      // 选中数组
      ids: [],
      // 非单个禁用
      single: true,
      // 非多个禁用
      multiple: true,
      //存储实验室
      selLabManageList: [],
      //存储仪器分类
      selDeviceTypeList: [],
      //用来保存检测报告信息
      RecordListRes: null,
      //用来存储修改的临时文件路径
      updateUrl: null,
      updateUrl2: null,
      updateUrl3: null,
    };
  },
  authorize: {
    deleteRecord: "delete",
  },
  created() {
    this.getList();
  },
  mounted() {
    this.getlabManageList();
    this.getDeviceTypeList();
  },
  methods: {
    delFileMethod(e) {
      delFile({ fileUrl: e }).then((res) => {});
    },
    //图片上传
    pictureCustomRequest(info) {
      const formData = new FormData();
      formData.append("file", info.file);

      if (this.form.picture != null && this.updateUrl != this.form.picture) {
        this.delFileMethod(this.form.picture);
      }

      uploadFile(formData).then((res) => {
        this.form.picture = res.data.data.fileUrl;
      });
    },
    //图片上传前
    pictureBeforeUpload(file) {
      const isJpgOrPng =
        file.type === "image/jpeg" || file.type === "image/png";
      if (!isJpgOrPng) {
        message.warning("只能上传图片!");
      }
      const isLt5M = file.size / 1024 / 1024 < 5;

      if (!isLt5M) {
        message.warning("图片大小不能超过5M!");
      }
      return isJpgOrPng && isLt5M;
    },
    //合同上传
    contractUrlCustomRequest(info) {
      if (
        this.form.contractUrl != null &&
        this.updateUrl2 != this.form.contractUrl
      ) {
        this.delFileMethod(this.form.contractUrl);
      }
      const formData = new FormData();
      formData.append("file", info.file);
      uploadFile(formData).then((res) => {
        this.form.contractUrl = res.data.data.fileUrl;
      });
    },
    //合同上传前
    contractUrlBeforeUpload(file) {
      return true;
    },
    //发票上传
    invoiceUrlCustomRequest(info) {
      const formData = new FormData();
      formData.append("file", info.file);

      if (
        this.form.invoiceUrl != null &&
        this.updateUrl3 != this.form.invoiceUrl
      ) {
        this.delFileMethod(this.form.invoiceUrl);
      }
      uploadFile(formData).then((res) => {
        this.form.invoiceUrl = res.data.data.fileUrl;
      });
    },
    //发票上传前
    invoiceUrlBeforeUpload(file) {
      return true;
    },
    //获取实验室
    getlabManageList() {
      LaboratoryListAll().then((res) => {
        var data = res.data;
        this.selLabManageList = data.data;
      });
    },
    //获取仪器分类
    getDeviceTypeList() {
      DeviceTypeListAll().then((res) => {
        var data = res.data;
        this.selDeviceTypeList = data.data;
      });
    },
    onShowSizeChange(current, pageSize) {
      this.queryParams.current = current;
      this.queryParams.size = pageSize;
      this.getList();
    },
    onPageChange(pageNumber) {
      if (this.form.picture != null && this.updateUrl != this.form.picture) {
        this.delFileMethod(this.form.picture);
      }
      //2
      if (
        this.form.contractUrl != null &&
        this.updateUrl2 != this.form.contractUrl
      ) {
        this.delFileMethod(this.form.contractUrl);
      }
      //3
      if (
        this.form.invoiceUrl != null &&
        this.updateUrl3 != this.form.invoiceUrl
      ) {
        this.delFileMethod(this.form.invoiceUrl);
      }
      this.queryParams.current = pageNumber;
      this.getList();
    },
    //获取设备列表
    getList() {
      DeviceList(this.queryParams).then((res) => {
        var data = res.data;
        this.dataSource = data.data.records;
        this.total = data.data.total;
      });
    },
    //查询数据
    handleSearch() {
      this.getList();
    },
    handleOk(e) {
      if (
        !this.form.name ||
        !this.form.laboratoryId ||
        !this.form.typeId ||
        !this.form.deviceAdmin
      ) {
        message.warning("缺少必填参数!");
        return;
      }
      this.submitForm();
    },

    handleCancel(e) {
      if (this.form.picture != null && this.updateUrl != this.form.picture) {
        this.delFileMethod(this.form.picture);
      }
      if (
        this.form.contractUrl != null &&
        this.updateUrl2 != this.form.contractUrl
      ) {
        this.delFileMethod(this.form.contractUrl);
      }
      if (
        this.form.invoiceUrl != null &&
        this.updateUr3 != this.form.invoiceUrl
      ) {
        this.delFileMethod(this.form.invoiceUrl);
      }
      this.form = {};
      this.open = false;
    },
    handleCancelAr() {
      this.openAr = false;
    },
    deleteRecord(key) {
      this.dataSource = this.dataSource.filter((item) => item.key !== key);
      this.selectedRows = this.selectedRows.filter((item) => item.key !== key);
    },
    toggleAdvanced() {
      this.advanced = !this.advanced;
    },
    remove() {
      this.dataSource = this.dataSource.filter(
        (item) =>
          this.selectedRows.findIndex((row) => row.key === item.key) === -1
      );
      this.selectedRows = [];
    },
    onSelectChange(selection) {
      this.ids = selection.map((item) => item.id);
      this.single = selection.length !== 1;
      this.multiple = !selection.length;
      this.selectedRowKeys = selection;
    },
    /** 新增按钮操作 */
    handleAdd() {
      this.open = true;
      this.title = "添加设备";
    },
    /**添加报告按钮操作 */
    hanleAr() {
      RecordList({
        current: 1,
        size: 5,
        code: this.selectedRowKeys[0],
      }).then((res) => {
        this.RecordListRes = res;
        this.openAr = true;
        this.title = "设备检查报告管理";
      });
    },
    /** 修改按钮操作 */
    handleUpdate(row) {
      this.loading = true;
      getDevice(this.selectedRowKeys[0]).then((response) => {
        this.loading = false;
        this.form = response.data.data;
        this.open = true;
        this.title = "修改设备基础信息";
        //1
        this.updateUrl = response.data.data.picture;
        //2
        this.updateUrl2 = response.data.data.contractUrl;
        //3
        this.updateUrl3 = response.data.data.invoiceUrl;
      });
    },
    /** 提交按钮 */
    submitForm() {
      this.buttonLoading = true;
      if (this.form.id != null) {
        //1
        if (this.form.picture != this.updateUrl) {
          this.delFileMethod(this.updateUrl);
        }
        //2
        if (this.form.contractUrl != this.updateUrl2) {
          this.delFileMethod(this.updateUrl2);
        }
        //3
        if (this.form.invoiceUrl != this.updateUrl3) {
          this.delFileMethod(this.updateUrl3);
        }
        editDevice(this.form)
          .then((response) => {
            this.open = false;
            this.form = {};
            this.getList();
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      } else {
        addDevice(this.form)
          .then((response) => {
            this.open = false;
            this.form = {};
            this.getList();
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      }
    },
    handleDel() {
      delDevice(this.selectedRowKeys)
        .then((response) => {
          this.selectedRowKeys = [];
          this.getList();
        })
        .finally(() => {
          this.buttonLoading = false;
        });
    },
  },
};
</script>

<style lang="less" scoped>
.ant-input-number {
  width: 100%;
}
.search {
  margin-bottom: 54px;
}
.fold {
  width: calc(100% - 216px);
  display: inline-block;
}
.operator {
  margin-bottom: 18px;
}
@media screen and (max-width: 900px) {
  .fold {
    width: 100%;
  }
}
</style>
