<template>
  <a-card>
    <div :class="advanced ? 'search' : null">
      <a-form layout="horizontal">
        <div class="fold">
          <a-row v-if="this.form.id != null">
            <a-col :md="8" :sm="24">
              <a-form-item label="报告编号">
                <a-input disabled v-model:value="form.id" />
              </a-form-item>
            </a-col>
            <a-col :md="8" :sm="24">
              <a-form-item label="设备编号">
                <a-input v-model:value="form.code" disabled />
              </a-form-item>
            </a-col>
            <a-col :md="8" :sm="24">
              <a-form-item label="设备名称">
                <a-input disabled v-model:value="form.name" />
              </a-form-item>
            </a-col>
          </a-row>
          <a-row>
            <a-col :md="8" :sm="24">
              <a-form-item label="经办人员">
                <a-input
                  placeholder="请输入经办人员"
                  v-model:value="form.operate"
                />
              </a-form-item>
            </a-col>
            <a-col :md="8" :sm="24">
              <a-form-item label="鉴定结果">
                <a-input
                  v-model:value="form.appraisalResult"
                  placeholder="请输入鉴定结果"
                />
              </a-form-item>
            </a-col>
            <a-col :md="8" :sm="24">
              <a-form-item label="鉴定日期">
                <a-date-picker
                  v-model:value="form.appraisalDate"
                  type="date"
                  valueFormat="yyyy-MM-DD"
                  placeholder="请选择鉴定日期"
                  style="width: 100%"
                />
              </a-form-item>
            </a-col>
          </a-row>
          <a-row>
            <a-col :md="8" :sm="24">
              <a-form-item label="相关资料" :rules="[{ required: true }]">
                <a-input v-model:value="form.fileUrl" disabled />
                <a-upload
                  v-model:file="file"
                  :show-upload-list="false"
                  :customRequest="customRequest"
                  :before-upload="beforeUpload"
                >
                  <a-button v-if="form.fileUrl">
                    <UploadOutlined></UploadOutlined>
                    点击修改相关资料
                  </a-button>
                  <a-button v-else>
                    <UploadOutlined></UploadOutlined>
                    点击上传相关资料
                  </a-button>
                </a-upload>
              </a-form-item>
            </a-col>
          </a-row>
        </div>
        <span style="float: right; margin-top: 30px">
          <a-button type="primary" @click="handleOk">{{
            form.id == null ? "添加" : "保存"
          }}</a-button>
          <a-button style="margin-left: 8px" @click="reset">重置</a-button>
        </span>
      </a-form>
    </div>
    <div>
      <a-space class="operator">
        <a-button @click="handleAdd" type="primary" v-if="form.id != null"
          >切换添加</a-button
        >
        <a-button
          v-if="form.id == null"
          @click="handleUpdate"
          type="primary"
          :disabled="selectedRowKeys.length == 1 ? false : true"
          >编辑</a-button
        >
        <a-button
          @click="handleDel"
          type="primary"
          :disabled="selectedRowKeys.length > 0 ? false : true"
          danger
          >删除
        </a-button>
      </a-space>
      <a-table
        rowKey="id"
        :pagination="false"
        :columns="columns"
        :data-source="dataSource"
        :row-selection="{
          selectedRowKeys: selectedRowKeys,
          onChange: onSelectChange,
        }"
      >
      </a-table>
      <a-pagination
        v-show="total > 0"
        show-size-changer
        :show-total="(total) => `共 ${total} 条`"
        v-model:current="queryParams.current"
        v-model:pageSize="queryParams.size"
        :total="total"
        show-less-items
        @showSizeChange="onShowSizeChange"
        @change="onPageChange"
      />
    </div>
  </a-card>
</template>

<script>
const columns = [
  {
    title: "编号",
    dataIndex: "id",
  },
  {
    title: "设备名称",
    dataIndex: "name",
  },
  {
    title: "设备编号",
    dataIndex: "code",
  },
  {
    title: "鉴定日期",
    dataIndex: "appraisalDate",
  },
  {
    title: "经办人",
    dataIndex: "operate",
  },
  {
    title: "鉴定结果",
    dataIndex: "appraisalResult",
  },
];
import { UploadOutlined } from "@ant-design/icons-vue";
import {
  RecordList,
  addRecord,
  getRecord,
  delRecord,
  editRecord,
} from "@/server/http/api/Device";
import { message } from "ant-design-vue";
import { uploadFile, delFile } from "@/server/http/api/File";
import { number } from "echarts";
export default {
  name: "QueryList",
  components: { UploadOutlined },
  props: {
    Code: number,
    ResList: Object,
  },
  data() {
    return {
      // 弹出层标题
      title: "",
      // 是否显示弹出层
      open: false,
      advanced: false,
      columns: columns,
      dataSource: [],
      selectedRows: [],
      selectedRowKeys: [],
      // 表单参数
      form: { id: null },
      file: null,
      Pagination: {},
      total: 0,
      queryParams: {
        current: 1,
        size: 5,
        code: this.Code,
      },
      // 选中数组
      ids: [],
      // 非单个禁用
      single: true,
      // 非多个禁用
      multiple: true,
      fileList: [],
      //用来存储修改的临时文件路径
      updateUrl: null,
    };
  },
  authorize: {
    deleteRecord: "delete",
  },
  created() {
    this.form = {
      code: this.Code,
    };
    var data = this.ResList.data;
    this.dataSource = data.data.records;
    this.total = data.data.total;
  },
  watch: {
    ResList(res) {
      var data = res.data;
      this.dataSource = data.data.records;
      this.total = data.data.total;
    },
  },
  methods: {
    delFileMethod(e) {
      delFile({ fileUrl: e }).then((res) => {});
    },
    //资料上传
    customRequest(info) {
      const formData = new FormData();
      formData.append("file", info.file);
      if (this.form.fileUrl != null && this.updateUrl != this.form.fileUrl) {
        this.delFileMethod(this.form.fileUrl);
      }
      uploadFile(formData).then((res) => {
        this.form.fileUrl = res.data.data.fileUrl;
      });
    },
    //资料上传前
    beforeUpload(file) {
      // let fileFormat = file.name.substring(
      //   file.name.lastIndexOf(".") + 1,
      //   file.name.length
      // );
      // const isJpgOrPng =
      //   fileFormat === "doc" || fileFormat === "pdf" || fileFormat === "docx";
      // if (!isJpgOrPng) {
      //   message.warning("只能上传word和pdf!");
      // }
      return true;
    },
    onShowSizeChange(current, pageSize) {
      this.queryParams.current = current;
      this.queryParams.size = pageSize;
      this.getList();
    },
    onPageChange(pageNumber) {
      this.queryParams.current = pageNumber;
      this.getList();
    },
    //获取设备分类列表
    getList() {
      RecordList(this.queryParams).then((res) => {
        var data = res.data;
        this.dataSource = data.data.records;
        this.total = data.data.total;
      });
    },
    handleOk(e) {
      if (!this.form.fileUrl) {
        message.warning("缺少必填参数!");
        return;
      }
      this.submitForm();
    },
    handleCancel(e) {
      this.form = {
        code: this.Code,
      };
      this.open = false;
    },
    deleteRecord(key) {
      this.dataSource = this.dataSource.filter((item) => item.key !== key);
      this.selectedRows = this.selectedRows.filter((item) => item.key !== key);
    },
    toggleAdvanced() {
      this.advanced = !this.advanced;
    },
    remove() {
      this.dataSource = this.dataSource.filter(
        (item) =>
          this.selectedRows.findIndex((row) => row.key === item.key) === -1
      );
      this.selectedRows = [];
    },
    onSelectChange(selection) {
      this.ids = selection.map((item) => item.id);
      this.single = selection.length !== 1;
      this.multiple = !selection.length;
      this.selectedRowKeys = selection;
    },
    /** 新增按钮操作 */
    handleAdd() {
      this.form = {
        code: this.Code,
      };
    },
    /** 修改按钮操作 */
    handleUpdate(row) {
      this.loading = true;
      getRecord(this.selectedRowKeys[0]).then((response) => {
        this.loading = false;
        this.form = response.data.data;
        this.updateUrl = response.data.data.fileUrl;
      });
    },
    /** 提交按钮 */
    submitForm() {
      this.buttonLoading = true;
      if (this.form.id != null) {
        if (this.form.fileUrl != this.updateUrl) {
          this.delFileMethod(this.updateUrl);
        }
        editRecord(this.form)
          .then((response) => {
            this.open = false;
            this.form = {
              code: this.Code,
            };
            this.getList();
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      } else {
        addRecord(this.form)
          .then((response) => {
            this.form = {
              code: this.Code,
            };
            this.getList();
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      }
    },
    handleDel() {
      delRecord(this.selectedRowKeys)
        .then((response) => {
          this.selectedRowKeys = [];
          this.form = {
            code: this.Code,
          };
          this.getList();
        })
        .finally(() => {
          this.buttonLoading = false;
        });
    },
    reset() {
      if (this.form.fileUrl != null && this.updateUrl != this.form.fileUrl) {
        this.delFileMethod(this.form.fileUrl);
      }
      this.updateUrl = null;
      if (this.form.id != null) {
        this.handleUpdate(null);
      } else {
        this.form = {
          code: this.Code,
        };
      }
    },
  },
};
</script>

<style lang="less" scoped>
.search {
  margin-bottom: 54px;
}
.fold {
  width: calc(100% - 216px);
  display: inline-block;
}
.operator {
  margin-bottom: 18px;
}
@media screen and (max-width: 900px) {
  .fold {
    width: 100%;
  }
}
</style>
